   129→
   130→/// Strategy interface for selecting the next candidate hyper-parameters.
   131→pub trait HyperParameterTuner: Send + Sync {
   132→    /// Returns a new set of hyper-parameters based on the latest model metrics.
   133→    fn suggest(&mut self, metrics: &ModelMetrics) -> Option<HyperParameters>;
