   136→/// Reference strategy: exhaustive grid-search with random walk.
   137→///
   138→/// In production we would enumerate deterministically; here we randomise to
   139→/// avoid massive search space exploration in the example code.
   140→pub struct GridSearchTuner {
   141→    /// Search grid catalogued in a naive way. For large search spaces, a
   142→    /// smarter iterator would be required.
   143→    grid: Vec<HyperParameters>,
   144→    /// Keep track of which configurations have been tried.
   145→    tried: HashMap<String, ()>,
   146→}
   147→
   148→impl GridSearchTuner {
   149→    pub fn new(space: HyperParamSpace) -> Self {
   150→        let mut grid = Vec::new();
   151→        for lr in space.lr {
   152→            for batch in &space.batch_size {
   153→                for dropout in &space.dropout {
   154→                    let params = serde_json::json!({
   155→                        "learning_rate": lr,
   156→                        "batch_size": batch,
   157→                        "dropout": dropout,
   158→                    });
   159→                    grid.push(HyperParameters::new(params));
   160→                }
   161→            }
   162→        }
   163→        Self {
   164→            grid,
   165→            tried: HashMap::new(),
   166→        }
   167→    }
   168→}
   169→
   170→impl HyperParameterTuner for GridSearchTuner {
   171→    fn suggest(&mut self, metrics: &ModelMetrics) -> Option<HyperParameters> {
   172→        // If the model performs well enough, no need to tune.
   173→        if metrics.accuracy >= 0.97 {
   174→            info!(
   175→                "Model [{}] already meets accuracy target ({}). Skipping suggestion.",
   176→                metrics.model_id, metrics.accuracy
   177→            );
   178→            return None;
   179→        }
   180→
   181→        // Otherwise, randomly take an unseen configuration from the grid.
   182→        let mut rng = thread_rng();
   183→        self.grid.shuffle(&mut rng);
   184→
   185→        for params in &self.grid {
   186→            let fingerprint = serde_json::to_string(&params).ok()?;
   187→            if !self.tried.contains_key(&fingerprint) {
   188→                info!(
   189→                    "Suggesting new hyper-parameters for model [{}]: {}",
   190→                    metrics.model_id, fingerprint
   191→                );
   192→                self.tried.insert(fingerprint, ());
   193→                return Some(params.clone());
   194→            }
   195→        }
   196→
   197→        info!(
   198→            "Grid exhausted for model [{}]; no more hyper-parameters to try.",
   199→            metrics.model_id
   200→        );
   201→        None
   202→    }
   203→}
