   209→/// A generic observer that reacts to model metrics.
   210→///
   211→/// In a real-world system this trait would likely come from a common
   212→/// crate so that multiple modules can subscribe to events uniformly.
   213→pub trait MetricsObserver: Send + Sync {
   214→    fn on_metrics(&self, metrics: ModelMetrics);
   215→}
   216→
   217→/// Central hub that receives incoming metrics and dispatches them to
   218→/// registered observers. This plays the *Subject* role in the Observer pattern.
   219→pub struct MetricMonitor {
   220→    observers: Arc<Mutex<Vec<Arc<dyn MetricsObserver>>>>,
   221→    sender: Sender<ModelMetrics>,
   222→    _worker_handle: thread::JoinHandle<()>,
   223→}
   224→
   225→impl MetricMonitor {
   226→    /// Creates a new monitor with a background worker thread that forwards
   227→    /// metrics to observers. The channel is bounded to apply back-pressure in
   228→    /// pathological cases.
   229→    pub fn new(buffer: usize) -> Self {
   230→        let observers = Arc::new(Mutex::new(Vec::new()));
   231→        let (sender, receiver) = bounded::<ModelMetrics>(buffer);
   232→        let observers_clone = observers.clone();
   233→
   234→        let handle = thread::spawn(move || Self::run(receiver, observers_clone));
   235→
   236→        Self {
   237→            observers,
   238→            sender,
   239→            _worker_handle: handle,
   240→        }
   241→    }
   242→
   243→    /// Internal worker loop.
   244→    fn run(receiver: Receiver<ModelMetrics>, observers: Arc<Mutex<Vec<Arc<dyn MetricsObserver>>>>) {
   245→        for metrics in receiver.iter() {
   246→            debug!("MetricMonitor received metrics: {:?}", metrics);
   247→            let snapshot = {
   248→                // Take a snapshot to minimise lock contention duration.
   249→                observers.lock().unwrap().clone()
   250→            };
   251→            for obs in snapshot {
   252→                obs.on_metrics(metrics.clone());
   253→            }
   254→        }
   255→        info!("MetricMonitor worker terminating");
   256→    }
   257→
   258→    /// Register a new observer.
   259→    pub fn subscribe<O: MetricsObserver + 'static>(&self, observer: O) {
   260→        self.observers.lock().unwrap().push(Arc::new(observer));
   261→    }
   262→
   263→    /// Feed metrics into the monitor. Called by the system’s telemetry layer.
   264→    pub fn ingest(&self, metrics: ModelMetrics) {
   265→        if let Err(e) = self.sender.send(metrics) {
   266→            // Inbound side; losing metrics is severe – always log an error.
   267→            error!("Failed to dispatch metrics: {}", e);
   268→        }
   269→    }
   270→}
