   275→
   276→/// Observer that decides when to trigger re-training based on metrics and
   277→/// delegates hyper-parameter suggestion to an injected tuner (Strategy).
   278→pub struct RetrainTrigger<T: HyperParameterTuner> {
   279→    tuner: Mutex<T>,
   280→    model_ops: Arc<dyn ModelOps>,
   281→    /// Minimal gap (in seconds) between consecutive retraining events for the
   282→    /// same model. Prevents runaway retraining loops.
   283→    cooldown_secs: u64,
   284→    /// Track last retrain timestamp per model.
   285→    last_retrain: Mutex<HashMap<String, std::time::Instant>>,
   286→}
   287→
   288→impl<T> RetrainTrigger<T>
   289→where
   290→    T: HyperParameterTuner + 'static,
   291→{
   292→    pub fn new(tuner: T, model_ops: Arc<dyn ModelOps>, cooldown_secs: u64) -> Self {
   293→        Self {
   294→            tuner: Mutex::new(tuner),
   295→            model_ops,
   296→            cooldown_secs,
   297→            last_retrain: Mutex::new(HashMap::new()),
   298→        }
   299→    }
   300→}
   301→
   302→impl<T> MetricsObserver for RetrainTrigger<T>
   303→where
   304→    T: HyperParameterTuner + 'static,
   305→{
   306→    fn on_metrics(&self, metrics: ModelMetrics) {
   307→        let now = std::time::Instant::now();
   308→
   309→        // Respect cooldown.
   310→        {
   311→            let mut map = self.last_retrain.lock().unwrap();
   312→            if let Some(last) = map.get(&metrics.model_id) {
   313→                if now.duration_since(*last).as_secs() < self.cooldown_secs {
   314→                    debug!(
   315→                        "Cooldown active for model [{}], skipping retrain",
   316→                        metrics.model_id
   317→                    );
   318→                    return;
   319→                }
   320→            }
   321→        }
   322→
   323→        // Ask the strategy for new hyper-parameters.
   324→        let maybe_params = {
   325→            let mut tuner = self.tuner.lock().unwrap();
   326→            tuner.suggest(&metrics)
   327→        };
   328→
   329→        if let Some(params) = maybe_params {
   330→            info!(
   331→                "Triggering re-training for model [{}] with new parameters",
   332→                metrics.model_id
   333→            );
   334→            match self.model_ops.retrain(&metrics.model_id, params) {
   335→                Ok(_) => {
   336→                    self.last_retrain
   337→                        .lock()
   338→                        .unwrap()
   339→                        .insert(metrics.model_id.clone(), now);
   340→                    info!("Re-training job submitted successfully");
   341→                }
   342→                Err(e) => {
   343→                    error!("Failed to submit re-training job: {:?}", e);
   344→                }
   345→            }
   346→        }
   347→    }
   348→}
