     2→//! Module 53 – Hyper-Parameter Tuning & Monitoring Integration
     3→//! ----------------------------------------------------------
     4→//! This module glues together three major concerns in the VisuTility Orchestrator:
     5→//! 1. Live collection of model–performance metrics coming from Serving-Ops.
     6→//! 2. Observer-Pattern broadcast of those metrics to interested components.
     7→//! 3. Strategy-Pattern hyper-parameter tuning algorithms that leverage the
     8→//!    latest metrics to propose improved configurations.
     9→//!
    10→//! The module purposefully stays generic (no hard-coded CV model details) so it
    11→//! can be reused by any vision model registered in the internal Model-Registry.
    12→//!
    13→//! Key concepts implemented below:
    14→//! • ModelMetrics          – Lightweight, serializable metrics snapshot.
    15→//! • MetricsPublisher      – Observable broadcaster (tokio::broadcast).
    16→//! • HyperparameterTuner   – Strategy trait with async proposal interface.
    17→//! • GridTuner/BayesianTuner – Two concrete strategy implementations.
    18→//! • TunerFactory          – Factory-Pattern for runtime strategy selection.
    19→//! • AutoTuningService     – End-to-end orchestrator that wires everything up.
    20→//!
    21→//! Author: VisuTility Core Team
    22→//! License: Apache-2.0
    23→
    24→use std::{
    25→    collections::{HashMap, VecDeque},
    26→    sync::Arc,
    27→    time::{Duration, Instant},
    28→};
    29→
    30→use anyhow::{anyhow, Context, Result};
    31→use async_trait::async_trait;
    32→use log::{debug, error, info, warn};
    33→use rand::{distributions::Uniform, prelude::Distribution, rngs::ThreadRng};
    34→use serde::{Deserialize, Serialize};
    35→use tokio::sync::{broadcast, Mutex};
    36→use tokio::time;
    37→
    38→/// A minimal set of model-quality metrics we care about during tuning.
    39→#[derive(Debug, Clone, Serialize, Deserialize)]
    40→pub struct ModelMetrics {
    41→    /// Overall model accuracy over the most recent validation window.
    42→    pub accuracy: f32,
    43→    /// Mean inference latency in milliseconds.
    44→    pub latency_ms: f32,
    45→    /// Timestamp when the metrics were recorded.
    46→    pub captured_at: Instant,
    47→}
    48→
    49→impl ModelMetrics {
    50→    pub fn is_good_enough(&self, min_accuracy: f32, max_latency: f32) -> bool {
    51→        self.accuracy >= min_accuracy && self.latency_ms <= max_latency
    52→    }
    53→}
    54→
    55→/* -------------------------------------------------------------------------- */
    56→/*                       Observer Pattern – Metrics Bus                       */
    57→/* -------------------------------------------------------------------------- */
    58→
    59→/// Buffer size used for the broadcast channel.
    60→const METRICS_BUFFER: usize = 128;
    61→
    62→/// Component that publishes `ModelMetrics` events so that any number of
    63→/// subscribers can react (e.g. dashboards, alerting, tuners, auditors).
    64→#[derive(Clone)]
    65→pub struct MetricsPublisher {
    66→    inner: broadcast::Sender<ModelMetrics>,
    67→}
    68→
    69→impl MetricsPublisher {
    70→    /// Create a new publisher / broadcast channel.
    71→    pub fn new() -> Self {
    72→        let (tx, _rx) = broadcast::channel(METRICS_BUFFER);
    73→        Self { inner: tx }
    74→    }
    75→
    76→    /// Send a metrics snapshot to all subscribers, logging on error.
    77→    pub fn publish(&self, metrics: ModelMetrics) {
    78→        if let Err(err) = self.inner.send(metrics) {
    79→            warn!("MetricsPublisher: failed to broadcast metrics: {err}");
    80→        }
    81→    }
    82→
    83→    /// Register a new subscriber for the metrics stream.
    84→    pub fn subscribe(&self) -> broadcast::Receiver<ModelMetrics> {
    85→        self.inner.subscribe()
    86→    }
    87→}
    88→
    89→/* -------------------------------------------------------------------------- */
    90→/*              Strategy Pattern – Hyper-parameter Tuning Trait              */
    91→/* -------------------------------------------------------------------------- */
    92→
    93→/// Canonical list of tunable hyper-parameters for computer-vision models.
    94→/// This is intentionally generic; individual model adapters perform mapping
    95→/// between these and their low-level framework/graph parameters.
    96→#[derive(Debug, Clone, Serialize, Deserialize, PartialEq)]
    97→pub struct HyperParams {
    98→    pub learning_rate: f32,
    99→    pub weight_decay: f32,
   100→    pub batch_size: usize,
   101→    pub augmentation_prob: f32,
   102→}
   103→
   104→impl Default for HyperParams {
   105→    fn default() -> Self {
   106→        Self {
   107→            learning_rate: 3e-4,
   108→            weight_decay: 1e-2,
   109→            batch_size: 32,
   110→            augmentation_prob: 0.5,
   111→        }
   112→    }
   113→}
   114→
   115→/// Behaviour that each tuning strategy must implement.
   116→#[async_trait]
   117→pub trait HyperparameterTuner: Send + Sync {
   118→    /// Consume recent metrics & propose a new hyper-parameters set.
   119→    async fn propose(
   120→        &mut self,
   121→        latest_metrics: &ModelMetrics,
   122→    ) -> Result<HyperParams>;
   123→
   124→    /// Optional hook so that external orchestration code can name the strategy.
   125→    fn name(&self) -> &'static str;
   126→}
   127→
   128→/* ----------------------- Concrete Strategy: Grid Search ------------------- */
   129→
   130→/// Very small fixed search-space grid-search tuner.
   131→/// Good as a baseline and for deterministic troubleshooting sessions.
   132→pub struct GridTuner {
   133→    grid: Vec<HyperParams>,
   134→    cursor: usize,
   135→}
   136→
   137→impl GridTuner {
   138→    pub fn new() -> Self {
   139→        // Build a tiny but combinatorically diverse grid.
   140→        let learning_rates = vec![1e-3, 3e-4, 1e-4];
   141→        let weight_decays = vec![1e-1, 1e-2];
   142→        let batch_sizes = vec![16, 32, 64];
   143→        let aug_probs = vec![0.3, 0.5, 0.8];
   144→
   145→        let mut grid = Vec::new();
   146→        for lr in &learning_rates {
   147→            for wd in &weight_decays {
   148→                for bs in &batch_sizes {
   149→                    for ap in &aug_probs {
   150→                        grid.push(HyperParams {
   151→                            learning_rate: *lr,
   152→                            weight_decay: *wd,
   153→                            batch_size: *bs,
   154→                            augmentation_prob: *ap,
   155→                        });
   156→                    }
   157→                }
   158→            }
   159→        }
   160→
   161→        Self { grid, cursor: 0 }
   162→    }
   163→}
   164→
   165→#[async_trait]
   166→impl HyperparameterTuner for GridTuner {
   167→    async fn propose(
   168→        &mut self,
   169→        _latest_metrics: &ModelMetrics,
   170→    ) -> Result<HyperParams> {
   171→        if self.cursor >= self.grid.len() {
   172→            return Err(anyhow!("GridTuner has exhausted its search space"));
   173→        }
   174→        let proposal = self.grid[self.cursor].clone();
   175→        self.cursor += 1;
   176→        Ok(proposal)
   177→    }
   178→
   179→    fn name(&self) -> &'static str {
   180→        "GridTuner"
   181→    }
   182→}
   183→
   184→/* --------------------- Concrete Strategy: Bayesian Tuner ------------------ */
   185→
   186→/// Crude Bayesian optimisation tuner using a Gaussian-like exploration.
   187→/// In production we would leverage a dedicated crate (e.g., `bayes_opt`),
   188→/// but for this reference implementation we keep it self-contained.
   189→pub struct BayesianTuner {
   190→    rng: ThreadRng,
   191→    /// History of tried params and their resulting accuracy so we can
   192→    /// bias towards the best ones (simplified Thompson Sampling).
   193→    history: VecDeque<(HyperParams, f32 /* accuracy */)>,
   194→    /// Maximum amount of history entries to keep in memory.
   195→    history_capacity: usize,
   196→}
   197→
   198→impl BayesianTuner {
   199→    pub fn new() -> Self {
   200→        Self {
   201→            rng: rand::thread_rng(),
   202→            history: VecDeque::new(),
   203→            history_capacity: 200,
   204→        }
   205→    }
   206→
   207→    /// Internal helper that returns a weighted sampling distribution over
   208→    /// previous params (higher accuracy → higher weight).
   209→    fn weighted_sample(&mut self) -> Option<HyperParams> {
   210→        if self.history.is_empty() {
   211→            return None;
   212→        }
   213→        // Build CDF based on accuracy.
   214→        let total_acc: f32 = self.history.iter().map(|(_, acc)| acc).sum();
   215→        if total_acc == 0.0 {
   216→            return None;
   217→        }
   218→        let mut rng_val: f32 = rand::random();
   219→        for (params, acc) in self.history.iter() {
   220→            rng_val -= *acc / total_acc;
   221→            if rng_val <= 0.0 {
   222→                return Some(params.clone());
   223→            }
   224→        }
   225→        self.history.back().map(|(p, _)| p.clone())
   226→    }
   227→}
   228→
   229→#[async_trait]
   230→impl HyperparameterTuner for BayesianTuner {
   231→    async fn propose(
   232→        &mut self,
   233→        latest_metrics: &ModelMetrics,
   234→    ) -> Result<HyperParams> {
   235→        // Persist the last known good params and accuracy for future sampling.
   236→        if let Some(prev) = self.history.back() {
   237→            // Only store if the model is improving and the change is meaningful.
   238→            if latest_metrics.accuracy > prev.1 + 0.002 {
   239→                let mut entry = prev.clone();
   240→                entry.1 = latest_metrics.accuracy;
   241→                self.history.push_back(entry);
   242→                if self.history.len() > self.history_capacity {
   243→                    self.history.pop_front();
   244→                }
   245→            }
   246→        }
   247→
   248→        // Either sample near a historically good configuration or sample random.
   249→        let base = self.weighted_sample().unwrap_or_else(|| HyperParams::default());
   250→
   251→        // Jitter around the base parameters.
   252→        let lr_dist = Uniform::new(0.5, 1.5);
   253→        let wd_dist = Uniform::new(0.5, 1.5);
   254→        let aug_dist = Uniform::new(-0.1f32, 0.1f32);
   255→
   256→        let mut proposal = base.clone();
   257→        proposal.learning_rate *= lr_dist.sample(&mut self.rng);
   258→        proposal.weight_decay *= wd_dist.sample(&mut self.rng);
   259→        proposal.augmentation_prob =
   260→            (proposal.augmentation_prob + aug_dist.sample(&mut self.rng)).clamp(0.0, 1.0);
   261→        // Pick a nearby batch size (±1 step).
   262→        proposal.batch_size = match self.rng.gen_range(0..=2) {
   263→            0 if proposal.batch_size > 8 => proposal.batch_size / 2,
   264→            2 => proposal.batch_size * 2,
   265→            _ => proposal.batch_size,
   266→        }
   267→        .clamp(8, 256);
   268→
   269→        Ok(proposal)
   270→    }
   271→
   272→    fn name(&self) -> &'static str {
   273→        "BayesianTuner"
   274→    }
   275→}
