   277→/* -------------------------------------------------------------------------- */
   278→/*                           Factory Pattern – Builder                        */
   279→/* -------------------------------------------------------------------------- */
   280→
   281→/// Enumeration of all supported tuner implementations.
   282→#[derive(Debug, Clone, Copy)]
   283→pub enum TunerType {
   284→    Grid,
   285→    Bayesian,
   286→}
   287→
   288→pub struct TunerFactory;
   289→
   290→impl TunerFactory {
   291→    pub fn build(tuner: TunerType) -> Arc<Mutex<dyn HyperparameterTuner>> {
   292→        match tuner {
   293→            TunerType::Grid => Arc::new(Mutex::new(GridTuner::new())),
   294→            TunerType::Bayesian => Arc::new(Mutex::new(BayesianTuner::new())),
   295→        }
   296→    }
