   337→                                }
   338→                            }
   339→                            Err(_) => {
   340→                                // Upstream closed. Shutdown gracefully.
   341→                                break;
   342→                            }
   343→                        }
   344→                    }
   345→                    recv(ticker) -> _ => {
   346→                        // Heart-beat for logging / metrics integration.
