    49→/// Trait defining the contract for an adaptive hyper-parameter tuner.
    50→#[async_trait::async_trait]
    51→pub trait HyperParamTuner: Send + Sync {
    52→    /// Returns a new candidate configuration for evaluation.
    53→    async fn suggest(&self) -> Result<HyperParams, TunerError>;
    54→
    55→    /// Updates the tuner’s internal state with the trial outcome so it can
