   123→/// Random search tuner that samples uniformly from user-supplied ranges.
   124→/// Each range is inclusive.
   125→///
   126→/// NOTE: For continuous variables, the range is treated as continuous;
   127→/// for discrete variables, the caller can pass equal min==max to achieve
   128→/// deterministic behavior.
   129→pub struct RandomSearchTuner {
   130→    ranges: HashMap<String, (f64, f64)>,
   131→    max_trials: usize,
   132→    trials: usize,
   133→    history: Vec<(HyperParams, f64)>,
