   135→
   136→impl RandomSearchTuner {
   137→    pub fn new(ranges: HashMap<String, (f64, f64)>, max_trials: usize) -> Self {
   138→        Self {
   139→            ranges,
   140→            max_trials,
   141→            trials: 0,
   142→            history: Vec::new(),
   143→        }
   144→    }
   145→
   146→    fn random_sample(&self) -> HyperParams {
   147→        let mut rng = thread_rng();
   148→        self.ranges
   149→            .iter()
   150→            .map(|(k, (min, max))| (k.clone(), rng.gen_range(*min..=*max)))
   151→            .collect()
   152→    }
   153→}
