   155→impl HyperparameterTuner for RandomSearchTuner {
   156→    fn suggest(&mut self) -> Option<HyperParams> {
   157→        if self.trials >= self.max_trials {
   158→            None
   159→        } else {
   160→            self.trials += 1;
   161→            Some(self.random_sample())
   162→        }
   163→    }
   164→
   165→    fn report_result(&mut self, params: &HyperParams, metric: f64) {
   166→        self.history.push((params.clone(), metric));
