    38→/// Public error type for the entire module
    39→#[derive(Debug, Error)]
    40→pub enum MonitorError {
    41→    #[error("IPC channel disconnected")]
    42→    ChannelDisconnected,
    43→    #[error("Experiment failed: {0}")]
    44→    ExperimentFailed(String),
    45→    #[error("Hyper-parameter tuning error: {0}")]
    46→    HyperparamTuning(String),
    47→    #[error("IO error: {0}")]
    48→    Io(#[from] std::io::Error),
    49→    #[error("Serialization error: {0}")]
    50→    Serialization(#[from] serde_json::Error),
    51→    #[error("Internal mutex poisioned")]
    52→    Poisoned,
    53→}
    54→
    55→/// A single snapshot of model-performance metrics.
    56→#[derive(Debug, Clone, Serialize, Deserialize)]
    57→pub struct ModelMetrics {
    58→    pub model_name: String,
    59→    pub version: String,
    60→    pub accuracy: f32,
    61→    pub precision: f32,
    62→    pub recall: f32,
    63→    pub timestamp: DateTime<Utc>,
    64→}
    65→
    66→/// The event that flows through the Observer pipeline.
    67→#[derive(Debug, Clone, Serialize, Deserialize)]
    68→pub enum ModelEvent {
    69→    Metrics(ModelMetrics),
    70→    // In a real system additional event variants would live here, e.g.
    71→    // SchemaDriftDetected, DataQualityIssue, etc.
    72→}
    73→
    74→/// Observer pattern: who listens to events?
    75→pub trait Observer: Send + Sync + 'static {
    76→    fn on_event(&self, event: &ModelEvent) -> Result<(), MonitorError>;
    77→}
    78→
    79→/// Observer pattern: who emits events?
    80→pub trait Subject: Send + Sync + 'static {
    81→    fn register_observer(&mut self, obs: Arc<dyn Observer>);
    82→    fn deregister_observer(&mut self, obs_id: usize);
    83→    fn notify(&self, event: ModelEvent);
    84→}
