    86→/// Thread-safe, async model-monitor implementation.
    87→pub struct ModelMonitor {
    88→    observers: RwLock<Vec<Arc<dyn Observer>>>,
    89→    tx: UnboundedSender<ModelEvent>,
    90→}
    91→
    92→impl ModelMonitor {
    93→    pub fn new(buffer: usize) -> Arc<Self> {
    94→        let (tx, rx) = mpsc::unbounded_channel();
    95→        let monitor = Arc::new(Self {
    96→            observers: RwLock::new(Vec::new()),
    97→            tx,
    98→        });
    99→
   100→        // Spawn async dispatcher
   101→        ModelMonitor::spawn_dispatch_loop(Arc::clone(&monitor), rx, buffer);
   102→
   103→        monitor
   104→    }
   105→
   106→    /// Non-blocking send of new events
   107→    pub fn submit_event(&self, event: ModelEvent) -> Result<(), MonitorError> {
   108→        self.tx
   109→            .send(event)
   110→            .map_err(|_| MonitorError::ChannelDisconnected)
   111→    }
   112→
   113→    fn spawn_dispatch_loop(
   114→        monitor: Arc<ModelMonitor>,
   115→        mut rx: UnboundedReceiver<ModelEvent>,
   116→        _buffer: usize,
   117→    ) {
   118→        task::spawn(async move {
   119→            while let Some(event) = rx.recv().await {
   120→                monitor.notify(event);
   121→            }
   122→        });
   123→    }
   124→}
   125→
   126→impl Subject for ModelMonitor {
   127→    fn register_observer(&mut self, obs: Arc<dyn Observer>) {
   128→        let mut guard = self
   129→            .observers
   130→            .write()
   131→            .expect("ModelMonitor observer lock poisoned");
   132→        guard.push(obs);
   133→    }
   134→
   135→    fn deregister_observer(&mut self, obs_id: usize) {
   136→        let mut guard = self
   137→            .observers
   138→            .write()
   139→            .expect("ModelMonitor observer lock poisoned");
   140→        if obs_id < guard.len() {
   141→            guard.remove(obs_id);
   142→        }
   143→    }
   144→
   145→    fn notify(&self, event: ModelEvent) {
   146→        let guard = self
   147→            .observers
   148→            .read()
   149→            .expect("ModelMonitor observer lock poisoned");
   150→        for obs in guard.iter() {
   151→            // Fire & forget; each observer must handle its own failure modes
   152→            let evt = event.clone();
   153→            let obs = Arc::clone(obs);
   154→            task::spawn(async move {
   155→                if let Err(e) = obs.on_event(&evt) {
   156→                    eprintln!("Observer failed to handle event: {e}");
   157→                }
   158→            });
   159→        }
   160→    }
   161→}
