   163→/// Hyper-parameter tuning strategy pattern
   164→pub trait HyperparamTuningStrategy: Send + Sync + 'static {
   165→    fn tune(
   166→        &self,
   167→        experiment_id: &str,
   168→        dataset_path: &Path,
   169→    ) -> Result<HyperparamSet, MonitorError>;
   170→}
   171→
   172→/// Concrete hyper-param tuning via random search
   173→pub struct RandomSearchStrategy {
   174→    pub max_trials: usize,
   175→}
   176→
   177→impl HyperparamTuningStrategy for RandomSearchStrategy {
   178→    fn tune(
   179→        &self,
   180→        experiment_id: &str,
   181→        _dataset_path: &Path,
   182→    ) -> Result<HyperparamSet, MonitorError> {
   183→        println!(
   184→            "RandomSearchStrategy: starting experiment {experiment_id} ({} trials)",
   185→            self.max_trials
   186→        );
   187→
   188→        let mut rng = rand::thread_rng();
   189→        let range = Uniform::new(0.0, 1.0);
   190→        let mut best_score = 0.0;
   191→        let mut best_params = HashMap::new();
   192→
   193→        for trial in 0..self.max_trials {
   194→            let lr = rng.sample(range);     // learning rate
   195→            let dropout = rng.sample(range); // dropout
   196→            let score = rng.sample(range);   // pretend validation accuracy
   197→
   198→            println!(
   199→                "Trial {trial}: lr={lr:.4}, dropout={dropout:.2} => val_acc={score:.3}"
   200→            );
   201→
   202→            if score > best_score {
   203→                best_score = score;
   204→                best_params.insert("learning_rate".into(), lr.to_string());
   205→                best_params.insert("dropout".into(), dropout.to_string());
   206→            }
   207→        }
   208→
   209→        Ok(HyperparamSet {
   210→            params: best_params,
   211→            score: best_score,
   212→        })
   213→    }
   214→}
