   216→/// A set of tuned hyper-parameters and its validation score
   217→#[derive(Debug, Clone, Serialize, Deserialize)]
   218→pub struct HyperparamSet {
   219→    pub params: HashMap<String, String>,
   220→    pub score: f32,
   221→}
