   223→/// Simplified experiment tracker
   224→pub struct ExperimentTracker {
   225→    log_path: PathBuf,
   226→    inner: Mutex<()>, // serialize writes
   227→}
   228→
   229→impl ExperimentTracker {
   230→    pub fn new<P: Into<PathBuf>>(log_path: P) -> Self {
   231→        Self {
   232→            log_path: log_path.into(),
   233→            inner: Mutex::new(()),
   234→        }
   235→    }
   236→
   237→    pub fn record(
   238→        &self,
   239→        experiment_id: &str,
   240→        hyperparams: &HyperparamSet,
   241→    ) -> Result<(), MonitorError> {
   242→        let json = serde_json::to_string(hyperparams)?;
   243→        let _guard = self.inner.lock().map_err(|_| MonitorError::Poisoned)?;
   244→        std::fs::OpenOptions::new()
   245→            .create(true)
   246→            .append(true)
   247→            .open(&self.log_path)?
   248→            .write_all(format!("{experiment_id},{json}\n").as_bytes())?;
   249→        Ok(())
   250→    }
   251→}
