   253→/// Observer that decides if a model should be retrained
   254→pub struct RetrainTrigger {
   255→    /// Minimum accuracy we accept before retraining
   256→    pub min_accuracy: f32,
   257→    pub tuner: Arc<dyn HyperparamTuningStrategy>,
   258→    pub tracker: Arc<ExperimentTracker>,
   259→    pub dataset_path: PathBuf,
   260→}
   261→
   262→impl Observer for RetrainTrigger {
   263→    fn on_event(&self, event: &ModelEvent) -> Result<(), MonitorError> {
   264→        match event {
   265→            ModelEvent::Metrics(metrics) => {
   266→                if metrics.accuracy < self.min_accuracy {
   267→                    println!(
   268→                        "RetrainTrigger: accuracy {:.3} below threshold {:.3}",
   269→                        metrics.accuracy, self.min_accuracy
   270→                    );
   271→                    let experiment_id =
   272→                        format!("{}_{}_{:x}", metrics.model_name, metrics.version, rand::random::<u32>());
   273→                    let tuner = Arc::clone(&self.tuner);
   274→                    let tracker = Arc::clone(&self.tracker);
   275→                    let dataset = self.dataset_path.clone();
   276→
   277→                    // Async retraining so we don't block monitoring loop
   278→                    task::spawn(async move {
   279→                        if let Err(e) =
   280→                            run_retraining(experiment_id, tuner, tracker, dataset).await
   281→                        {
   282→                            eprintln!("Retraining failed: {e}");
   283→                        }
   284→                    });
   285→                }
   286→            }
   287→        }
   288→        Ok(())
   289→    }
   290→}
