   292→/// Core retraining routine
   293→async fn run_retraining(
   294→    experiment_id: String,
   295→    tuner: Arc<dyn HyperparamTuningStrategy>,
   296→    tracker: Arc<ExperimentTracker>,
   297→    dataset: PathBuf,
   298→) -> Result<(), MonitorError> {
   299→    println!("Starting retraining experiment {experiment_id}");
   300→
   301→    let tuned = tuner.tune(&experiment_id, &dataset)?;
   302→    tracker.record(&experiment_id, &tuned)?;
   303→
   304→    // Simulate asynchronous model training
   305→    println!(
   306→        "Training model with best val_acc={:.3} and params={:?}",
   307→        tuned.score, tuned.params
   308→    );
   309→    sleep(Duration::from_secs(2)).await; // pretend training time
   310→
   311→    println!("Experiment {experiment_id} completed successfully");
   312→    Ok(())
   313→}
