    49→/// Domain-level errors surfaced by the hyper-parameter sub-system.
    50→#[derive(Debug, Error)]
    51→pub enum TuningError {
    52→    #[error("parameter `{0}` is missing")]
    53→    MissingParameter(String),
    54→
    55→    #[error("exhausted parameter space")]
    56→    ExhaustedSpace,
    57→
    58→    #[error("IO error: {0}")]
