    65→/// Primitive value supported in the parameter space.
    66→#[derive(Clone, Debug, Serialize, Deserialize, PartialEq)]
    67→#[serde(untagged)]
    68→pub enum ParamValue {
    69→    Int(i64),
    70→    Float(f64),
    71→    Str(String),
    72→}
    73→
    74→impl std::fmt::Display for ParamValue {
    75→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
    76→        match self {
    77→            ParamValue::Int(v) => write!(f, "{v}"),
    78→            ParamValue::Float(v) => write!(f, "{v:.4}"),
