    91→/// ----------------------------------------------------------------------------
    92→/// Strategy Pattern: core trait implemented by concrete tuners.
    93→/// ----------------------------------------------------------------------------
    94→pub trait Tuner: Send {
    95→    /// Produce the next candidate to evaluate.
    96→    fn next_candidate(&mut self) -> Result<Candidate>;
    97→
    98→    /// Notify the tuner that `score` (e.g. validation loss) was obtained for
    99→    /// `candidate`.  The tuner may use this information for adaptive search.
   100→    fn update_result(&mut self, candidate: &Candidate, score: f64) -> Result<()>;
   101→}
