   103→/// ----------------------------------------------------------------------------
   104→/// Grid-Search implementation
   105→/// ----------------------------------------------------------------------------
   106→pub struct GridSearchTuner {
   107→    space: ParamSpace,
   108→    cursor: Vec<usize>,
   109→    finished: bool,
   110→}
   111→
   112→impl GridSearchTuner {
   113→    pub fn new(space: ParamSpace) -> Self {
   114→        let cursor = vec![0; space.len()];
   115→        Self {
   116→            space,
   117→            cursor,
   118→            finished: false,
   119→        }
   120→    }
   121→
   122→    /// Helper for mapping the internal cursor into a concrete `Candidate`.
   123→    fn cursor_to_candidate(&self) -> Candidate {
   124→        let mut cand = Candidate::new();
   125→        for ((key, values), idx) in self.space.iter().zip(self.cursor.iter()) {
   126→            cand.insert(key.clone(), values[*idx].clone());
   127→        }
   128→        cand
   129→    }
   130→
   131→    /// Advances the multi-dimensional cursor.  Returns `false` if wrapped-around
   132→    /// and the entire grid was already enumerated.
   133→    fn increment_cursor(&mut self) -> bool {
   134→        for (dim_idx, (_, values)) in self.space.iter().enumerate().rev() {
   135→            let limit = values.len();
   136→            self.cursor[dim_idx] += 1;
   137→            if self.cursor[dim_idx] < limit {
   138→                return true; // simple increment in this dimension
   139→            } else {
   140→                self.cursor[dim_idx] = 0; // carry-over to higher dimension
   141→            }
   142→        }
   143→        false // all dimensions wrapped
   144→    }
   145→}
