   148→    fn next_candidate(&mut self) -> Result<Candidate> {
   149→        if self.finished {
   150→            return Err(TuningError::ExhaustedSpace);
   151→        }
   152→        let cand = self.cursor_to_candidate();
   153→        if !self.increment_cursor() {
   154→            self.finished = true;
   155→        }
   156→        Ok(cand)
   157→    }
   158→
   159→    fn update_result(&mut self, _candidate: &Candidate, _score: f64) -> Result<()> {
   160→        // Grid search is exhaustive & non-adaptive → nothing to do.
   161→        Ok(())
   162→    }
   163→}
