   165→/// ----------------------------------------------------------------------------
   166→/// Random-Search implementation
   167→/// ----------------------------------------------------------------------------
   168→pub struct RandomSearchTuner {
   169→    space: ParamSpace,
   170→    seen_hashes: HashSet<u64>, // prevent duplicates
   171→    max_trials: Option<usize>,
   172→}
   173→
   174→impl RandomSearchTuner {
   175→    pub fn new(space: ParamSpace, max_trials: Option<usize>) -> Self {
   176→        Self {
   177→            space,
   178→            seen_hashes: HashSet::new(),
   179→            max_trials,
   180→        }
