   238→/// ----------------------------------------------------------------------------
   239→/// Observer Pattern: EventBus for publishing & subscribing to metric events.
   240→/// ----------------------------------------------------------------------------
   241→
   242→/// Event emitted after a trial is finished.
   243→#[derive(Clone, Debug, Serialize)]
   244→pub struct TrialFinishedEvent {
   245→    pub candidate: Candidate,
   246→    pub score: f64,
   247→    pub finished_at: DateTime<Utc>,
   248→}
   249→
   250→/// Simple, in-process event bus backed by `parking_lot::RwLock`.
   251→#[derive(Default)]
   252→pub struct EventBus {
   253→    listeners: RwLock<Vec<Arc<dyn Fn(&TrialFinishedEvent) + Send + Sync>>>,
   254→}
   255→
   256→impl EventBus {
   257→    pub fn new() -> Self {
   258→        Self::default()
   259→    }
   260→
   261→    /// Subscribe a listener callback.  Returns a handle that can be `drop`ped to
   262→    /// unsubscribe (implemented via `Arc` ref-counting).
   263→    pub fn subscribe<F>(&self, listener: F) -> Arc<dyn Fn(&TrialFinishedEvent) + Send + Sync>
   264→    where
   265→        F: Fn(&TrialFinishedEvent) + Send + Sync + 'static,
   266→    {
   267→        let arc = Arc::new(listener);
   268→        self.listeners.write().push(arc.clone());
   269→        arc
   270→    }
   271→
   272→    pub fn dispatch(&self, evt: TrialFinishedEvent) {
   273→        for listener in self.listeners.read().iter() {
