   314→/// ----------------------------------------------------------------------------
   315→/// Glue-code tying everything together.
   316→/// ----------------------------------------------------------------------------
   317→pub struct HyperparameterRunner {
   318→    tuner: Box<dyn Tuner>,
   319→    bus: Arc<EventBus>,
   320→    trackers: Vec<Arc<dyn ExperimentTracker>>,
   321→}
   322→
   323→impl HyperparameterRunner {
   324→    pub fn new(
   325→        tuner: Box<dyn Tuner>,
   326→        bus: Arc<EventBus>,
   327→        trackers: Vec<Arc<dyn ExperimentTracker>>,
   328→    ) -> Self {
   329→        Self {
   330→            tuner,
   331→            bus,
   332→            trackers,
   333→        }
   334→    }
   335→
   336→    /// Blocking loop that pulls a candidate, executes user-provided evaluation
   337→    /// closure, and then broadcasts / logs the result.
   338→    pub fn run<Evaluate>(&mut self, mut eval_fn: Evaluate) -> Result<()>
   339→    where
   340→        Evaluate: FnMut(&Candidate) -> Result<f64>,
   341→    {
   342→        loop {
   343→            let cand = match self.tuner.next_candidate() {
   344→                Ok(c) => c,
   345→                Err(TuningError::ExhaustedSpace) => break,
   346→                Err(e) => return Err(e),
   347→            };
   348→
   349→            let score = eval_fn(&cand)?;
   350→            self.tuner.update_result(&cand, score)?;
   351→
   352→            let evt = TrialFinishedEvent {
   353→                candidate: cand,
   354→                score,
   355→                finished_at: Utc::now(),
   356→            };
   357→
   358→            // Send to event bus
   359→            self.bus.dispatch(evt.clone());
   360→
   361→            // Persist via trackers
   362→            for t in &self.trackers {
   363→                if let Err(e) = t.log_trial(&evt) {
   364→                    // non-fatal: log and keep going
   365→                    log::warn!("Experiment-tracker error: {e}");
   366→                }
   367→            }
   368→        }
   369→        Ok(())
   370→    }
   371→}
