   373→/// ----------------------------------------------------------------------------
   374→/// Convenience hash implementation for Candidate using `fxhash` for speed.
   375→/// ----------------------------------------------------------------------------
   376→mod fxhash {
   377→    #![allow(clippy::unseparated_literal_suffix)]
   378→    // 64-bit Fowler–Noll–Vo hash adapted for quick & dirty deduplication.
   379→    pub fn hash64(candidate: &super::Candidate) -> u64 {
   380→        let mut hash: u64 = 0xcbf29ce484222325;
   381→        for (k, v) in candidate {
   382→            for byte in k.as_bytes().iter().chain(v.to_string().as_bytes()) {
   383→                hash ^= *byte as u64;
   384→                hash = hash.wrapping_mul(0x00000100000001b3);
   385→            }
   386→        }
   387→        hash
   388→    }
   389→}
