     2→//! src/module_25.rs
     3→//!
     4→//! Experiment-tracking and hyper-parameter tuning utilities used by
     5→//! VisuTility Orchestrator’s Model-Ops layer.
     6→//!
     7→//! The module demonstrates a concrete implementation of several of the
     8→//! architectural patterns mentioned in the project documentation:
     9→//!   • Strategy Pattern: `HyperParamTuner` selects among tuning strategies
    10→//!     (`GridSearchTuner`, `RandomSearchTuner`, …).
    11→//!   • Observer Pattern: `TuningSubject` notifies `TuningObserver`s about new
    12→//!     trial results so that other subsystems (alerting, dashboards, etc.)
    13→//!     can react in real-time.
    14→//!   • Factory Pattern: `TrackerFactory` picks the correct
    15→//!     `ExperimentTracker` backend.
    16→//!
    17→//! All public types are designed to remain stable across minor releases so
    18→//! that external micro-services can rely on them via semantic versioning.
    19→
    20→use async_trait::async_trait;
    21→use rand::{seq::SliceRandom, Rng};
    22→use reqwest::Client;
    23→use serde::{Deserialize, Serialize};
    24→use serde_json::json;
    25→use std::{
    26→    collections::HashMap,
    27→    fs::{File, OpenOptions},
    28→    io::{BufWriter, Write},
    29→    path::PathBuf,
    30→    sync::{Arc, Mutex},
    31→};
    32→use thiserror::Error;
    33→use tokio::sync::broadcast;
    34→
    35→/// Domain-level error type.
    36→#[derive(Debug, Error)]
    37→pub enum OrchestratorError {
    38→    #[error("IO error: {0}")]
    39→    Io(#[from] std::io::Error),
    40→
    41→    #[error("HTTP error: {0}")]
    42→    Http(#[from] reqwest::Error),
    43→
    44→    #[error("Serialization error: {0}")]
    45→    Serde(#[from] serde_json::Error),
    46→
    47→    #[error("Broadcast channel error: {0}")]
    48→    BroadcastRecv(#[from] broadcast::error::RecvError),
    49→
    50→    #[error("Unknown error: {0}")]
    51→    Other(String),
    52→}
    53→
    54→/// Represents a concrete hyper-parameter value.
    55→///
    56→/// We purposefully remain JSON-compatible so that values can be directly
    57→/// serialized for experiment tracking.
    58→#[derive(Debug, Clone, Serialize, Deserialize)]
    59→#[serde(untagged)]
    60→pub enum HyperParamValue {
    61→    Int(i64),
    62→    Float(f64),
    63→    Text(String),
    64→    Bool(bool),
    65→}
    66→
    67→/// Full specification of a single trial.
    68→#[derive(Debug, Clone, Serialize, Deserialize)]
    69→pub struct Trial {
    70→    pub id: u64,
    71→    pub params: HashMap<String, HyperParamValue>,
    72→    pub metrics: HashMap<String, f64>,
    73→}
    74→
    75→/// Trait describing the capabilities of an experiment-tracker backend.
    76→///
    77→/// Implementations must be easy to swap at runtime.
    78→///
    79→/// NOTE: This trait is async because some backends perform network IO.
    80→#[async_trait]
    81→pub trait ExperimentTracker: Send + Sync {
    82→    async fn log_trial(&self, trial: &Trial) -> Result<(), OrchestratorError>;
    83→}
    84→
    85→/// Simple JSON-Lines file tracker.
    86→///
    87→/// Each trial is appended as a single JSON object on its own line.
    88→pub struct FileTracker {
    89→    /// Lazily-opened file handle wrapped in a Mutex for thread-safety.
    90→    file: Arc<Mutex<BufWriter<File>>>,
    91→}
    92→
    93→impl FileTracker {
    94→    pub fn new<P: Into<PathBuf>>(path: P) -> Result<Self, OrchestratorError> {
    95→        let file = OpenOptions::new()
    96→            .create(true)
    97→            .append(true)
    98→            .open(path.into())?;
    99→        Ok(Self {
   100→            file: Arc::new(Mutex::new(BufWriter::new(file))),
   101→        })
   102→    }
   103→}
   104→
   105→#[async_trait]
   106→impl ExperimentTracker for FileTracker {
   107→    async fn log_trial(&self, trial: &Trial) -> Result<(), OrchestratorError> {
   108→        let mut writer = self.file.lock().unwrap();
   109→        serde_json::to_writer(&mut *writer, trial)?;
   110→        writer.write_all(b"\n")?;
   111→        writer.flush()?;
   112→        Ok(())
   113→    }
   114→}
