   116→/// HTTP tracker that POSTs a JSON payload to a remote endpoint.
   117→pub struct HttpTracker {
   118→    endpoint: String,
   119→    client: Client,
   120→}
   121→
   122→impl HttpTracker {
   123→    pub fn new<S: Into<String>>(endpoint: S) -> Self {
   124→        Self {
   125→            endpoint: endpoint.into(),
   126→            client: Client::new(),
   127→        }
   128→    }
   129→}
   130→
   131→#[async_trait]
   132→impl ExperimentTracker for HttpTracker {
   133→    async fn log_trial(&self, trial: &Trial) -> Result<(), OrchestratorError> {
   134→        self.client
   135→            .post(&self.endpoint)
   136→            .json(trial)
   137→            .send()
   138→            .await?
   139→            .error_for_status()?;
   140→        Ok(())
   141→    }
   142→}
