   144→/// Factory pattern: pick an `ExperimentTracker` based on a declarative config.
   145→pub enum TrackerFactory {}
   146→
   147→impl TrackerFactory {
   148→    pub fn build(config: &TrackerConfig) -> Result<Arc<dyn ExperimentTracker>, OrchestratorError> {
   149→        match config {
   150→            TrackerConfig::File { path } => Ok(Arc::new(FileTracker::new(path)?)),
   151→            TrackerConfig::Http { endpoint } => Ok(Arc::new(HttpTracker::new(endpoint))),
   152→        }
   153→    }
   154→}
   155→
   156→/// Minimal config enum that can be deserialized from JSON/YAML/TOML.
   157→#[derive(Debug, Clone, Serialize, Deserialize)]
   158→#[serde(tag = "type", rename_all = "snake_case")]
   159→pub enum TrackerConfig {
   160→    File { path: PathBuf },
   161→    Http { endpoint: String },
   162→}
