   164→/// Observer pattern: observers react to new trial events.
   165→#[async_trait]
   166→pub trait TuningObserver: Send + Sync {
   167→    async fn on_new_trial(&self, trial: &Trial) -> Result<(), OrchestratorError>;
   168→}
   169→
   170→/// The subject that notifies all registered observers.
   171→pub struct TuningSubject {
   172→    tx: broadcast::Sender<Trial>,
   173→}
   174→
   175→impl TuningSubject {
   176→    pub fn new(buffer: usize) -> Self {
   177→        let (tx, _) = broadcast::channel(buffer);
   178→        Self { tx }
   179→    }
   180→
   181→    pub fn observer_stream(&self) -> broadcast::Receiver<Trial> {
   182→        self.tx.subscribe()
   183→    }
   184→
   185→    pub fn notify(&self, trial: Trial) -> Result<(), OrchestratorError> {
   186→        // If there are no observers, we ignore the error.
   187→        let _ = self.tx.send(trial);
   188→        Ok(())
   189→    }
   190→}
   191→
   192→/// Any hyper-parameter tuner must implement this trait.
   193→/// Strategies (grid search, random search, Bayesian, …) can be hot-swapped.
   194→#[async_trait]
   195→pub trait HyperParamTuner {
   196→    async fn run(
   197→        &mut self,
   198→        tracker: Arc<dyn ExperimentTracker>,
   199→        subject: Arc<TuningSubject>,
   200→    ) -> Result<(), OrchestratorError>;
   201→}
   202→
   203→/// Deterministic grid-search tuner.
   204→pub struct GridSearchTuner {
   205→    /// Each parameter maps to a list of possible discrete values.
   206→    /// Example: {"lr": [0.1, 0.01], "batch": [16, 32]}
   207→    param_grid: HashMap<String, Vec<HyperParamValue>>,
   208→    max_trials: Option<usize>,
   209→    current_trial_id: u64,
   210→}
   211→
   212→impl GridSearchTuner {
   213→    pub fn new(
   214→        param_grid: HashMap<String, Vec<HyperParamValue>>,
   215→        max_trials: Option<usize>,
   216→    ) -> Self {
   217→        Self {
   218→            param_grid,
   219→            max_trials,
   220→            current_trial_id: 0,
   221→        }
   222→    }
   223→
   224→    /// Helper that expands the grid into the Cartesian product.
   225→    fn expand_grid(
   226→        &self,
   227→    ) -> Vec<HashMap<String, HyperParamValue>> {
   228→        fn helper(
   229→            keys: &[String],
   230→            idx: usize,
   231→            grid: &HashMap<String, Vec<HyperParamValue>>,
   232→            acc: &mut HashMap<String, HyperParamValue>,
   233→            out: &mut Vec<HashMap<String, HyperParamValue>>,
   234→        ) {
   235→            if idx == keys.len() {
   236→                out.push(acc.clone());
   237→                return;
   238→            }
   239→            let key = &keys[idx];
   240→            if let Some(values) = grid.get(key) {
   241→                for val in values {
   242→                    acc.insert(key.clone(), val.clone());
   243→                    helper(keys, idx + 1, grid, acc, out);
   244→                    acc.remove(key);
   245→                }
   246→            }
   247→        }
   248→
   249→        let keys: Vec<String> = self.param_grid.keys().cloned().collect();
   250→        let mut out = Vec::new();
   251→        helper(&keys, 0, &self.param_grid, &mut HashMap::new(), &mut out);
   252→        out
   253→    }
   254→
   255→    /// Fake metric evaluator. In reality, this would invoke a real training
   256→    /// job and return its validation score. For demo purposes we sample a
   257→    /// random metric to keep the code fully functional without dependencies
   258→    /// on heavy ML frameworks.
   259→    async fn evaluate(
   260→        &mut self,
   261→        params: &HashMap<String, HyperParamValue>,
   262→    ) -> Result<HashMap<String, f64>, OrchestratorError> {
   263→        let mut rng = rand::thread_rng();
   264→        // Pretend lower is better for "loss".
   265→        Ok(HashMap::from([("loss".to_string(), rng.gen::<f64>())]))
   266→    }
   267→}
   268→
   269→#[async_trait]
   270→impl HyperParamTuner for GridSearchTuner {
   271→    async fn run(
   272→        &mut self,
   273→        tracker: Arc<dyn ExperimentTracker>,
   274→        subject: Arc<TuningSubject>,
   275→    ) -> Result<(), OrchestratorError> {
   276→        let combos = self.expand_grid();
   277→        let limit = self.max_trials.unwrap_or(combos.len());
   278→        for params in combos.into_iter().take(limit) {
   279→            let metrics = self.evaluate(&params).await?;
   280→            let trial = Trial {
   281→                id: self.current_trial_id,
   282→                params,
   283→                metrics,
   284→            };
   285→            self.current_trial_id += 1;
   286→
   287→            tracker.log_trial(&trial).await?;
   288→            subject.notify(trial)?;
   289→        }
   290→        Ok(())
   291→    }
   292→}
   293→
   294→/// Non-deterministic random-search tuner.
   295→pub struct RandomSearchTuner {
   296→    param_space: HashMap<String, Vec<HyperParamValue>>,
   297→    num_trials: usize,
   298→    current_trial_id: u64,
   299→}
   300→
   301→impl RandomSearchTuner {
   302→    pub fn new(param_space: HashMap<String, Vec<HyperParamValue>>, num_trials: usize) -> Self {
   303→        Self {
   304→            param_space,
   305→            num_trials,
   306→            current_trial_id: 0,
   307→        }
   308→    }
   309→
   310→    fn sample_params(&self) -> HashMap<String, HyperParamValue> {
   311→        let mut rng = rand::thread_rng();
   312→        self.param_space
   313→            .iter()
   314→            .map(|(k, v)| {
