Serialize, Deserialize)]\n#[serde(untagged)]\npub enum HyperParamValue {\n    Int(i64),\n    Float(f64),\n    Text(String),\n    Bool(bool),\n}\n\n/// Full specification of a single trial.\n#[derive(Debug, Clone, Serialize, Deserialize)]\npub struct Trial {\n    pub id: u64,\n    pub params: HashMap<String, HyperParamValue>,\n    pub metrics: HashMap<String, f64>,\n}\n\n/// Trait describing the capabilities of an experiment-tracker backend.\n///\n/// Implementations must be easy to swap at runtime.\n///\n/// NOTE: This trait is async because some backends perform network IO.\n#[async_trait]\npub trait ExperimentTracker: Send + Sync {\n    async fn log_trial(&self, trial: &Trial) -> Result<(), OrchestratorError>;\n}\n\n/// Simple JSON-Lines file tracker.\n///\n/// Each trial is appended as a single JSON object on its own line.\npub struct FileTracker {\n    /// Lazily-opened file handle wrapped in a Mutex for thread-safety.\n    file: Arc<Mutex<BufWriter<File>>>,\n}\n\nimpl FileTracker {\n    pub fn new<P: Into<PathBuf>>(path: P) -> Result<Self, OrchestratorError> {\n        let file = OpenOptions::new()\n            .create(true)\n            .append(true)\n            .open(path.into())?;\n        Ok(Self {\n            file: Arc::new(Mutex::new(BufWriter::new(file))),\n        })\n    }\n}\n\n#[async_trait]\nimpl ExperimentTracker for FileTracker {\n    async fn log_trial(&self, trial: &Trial) -> Result<(), OrchestratorError> {\n        let mut writer = self.file.lock().unwrap();\n        serde_json::to_writer(&mut *writer, trial)?;\n        writer.write_all(b\"\\n\")?;\n        writer.flush()?;\n        Ok(())\n    }\n}\n\n/// HTTP tracker that POSTs a JSON payload to a remote endpoint.\npub struct HttpTracker {\n    endpoint: String,\n    client: Client,\n}\n\nimpl HttpTracker {\n    pub fn new<S: Into<String>>(endpoint: S) -> Self {\n        Self {\n            endpoint: endpoint.into(),\n            client: Client::new(),\n        }\n    }\n}\n\n#[async_trait]\nimpl ExperimentTracker for HttpTracker {\n    async fn log_trial(&self, trial: &Trial) -> Result<(), OrchestratorError> {\n        self.client\n            .post(&self.endpoint)\n            .json(trial)\n            .send()\n            .await?\n            .error_for_status()?;\n        Ok(())\n    }\n}\n\n/// Factory pattern: pick an `ExperimentTracker` based on a declarative config.\npub enum TrackerFactory {}\n\nimpl TrackerFactory {\n    pub fn build(config: &TrackerConfig) -> Result<Arc<dyn ExperimentTracker>, OrchestratorError> {\n        match config {\n            TrackerConfig::File { path } => Ok(Arc::new(FileTracker::new(path)?)),\n            TrackerConfig::Http { endpoint } => Ok(Arc::new(HttpTracker::new(endpoint))),\n        }\n    }\n}\n\n/// Minimal config enum that can be deserialized from JSON/YAML/TOML.\n#[derive(Debug, Clone, Serialize, Deserialize)]\n#[serde(tag = \"type\", rename_all = \"snake_case\")]\npub enum TrackerConfig {\n    File { path: PathBuf },\n    Http { endpoint: String },\n}\n\n/// Observer pattern: observers react to new trial events.\n#[async_trait]\npub trait TuningObserver: Send + Sync {\n    async fn on_new_trial(&self, trial: &Trial) -> Result<(), OrchestratorError>;\n}\n\n/// The subject that notifies all registered observers.\npub struct TuningSubject {\n    tx: broadcast::Sender<Trial>,\n}\n\nimpl TuningSubject {\n    pub fn new(buffer: usize) -> Self {\n        let (tx, _) = broadcast::channel(buffer);\n        Self { tx }\n    }\n\n    pub fn observer_stream(&self) -> broadcast::Receiver<Trial> {\n        self.tx.subscribe()\n    }\n\n    pub fn notify(&self, trial: Trial) -> Result<(), OrchestratorError> {\n        // If there are no observers, we ignore the error.\n        let _ = self.tx.send(trial);\n        Ok(())\n    }\n}\n\n/// Any hyper-parameter tuner must implement this trait.\n/// Strategies (grid search, random search, Bayesian, …) can be hot-swapped.\n#[async_trait]\npub trait HyperParamTuner {\n    async fn run(\n        &mut self,\n        tracker: Arc<dyn ExperimentTracker>,\n        subject: Arc<TuningSubject>,\n    ) -> Result<(), OrchestratorError>;\n}\n\n/// Deterministic grid-search tuner.\npub struct GridSearchTuner {\n    /// Each parameter maps to a list of possible discrete values.\n    /// Example: {\"lr\": [0.1, 0.01], \"batch\": [16, 32]}\n    param_grid: HashMap<String, Vec<HyperParamValue>>,\n    max_trials: Option<usize>,\n    current_trial_id: u64,\n}\n\nimpl GridSearchTuner {\n    pub fn new(\n        param_grid: HashMap<String, Vec<HyperParamValue>>,\n        max_trials: Option<usize>,\n    ) -> Self {\n        Self {\n            param_grid,\n            max_trials,\n            current_trial_id: 0,\n        }\n    }\n\n    /// Helper that expands the grid into the Cartesian product.\n    fn expand_grid(\n        &self,\n    ) -> Vec<HashMap<String, HyperParamValue>> {\n        fn helper(\n            keys: &[String],\n            idx: usize,\n            grid: &HashMap<String, Vec<HyperParamValue>>,\n            acc: &mut HashMap<String, HyperParamValue>,\n            out: &mut Vec<HashMap<String, HyperParamValue>>,\n        ) {\n            if idx == keys.len() {\n                out.push(acc.clone());\n                return;\n            }\n            let key = &keys[idx];\n            if let Some(values) = grid.get(key) {\n                for val in values {\n                    acc.insert(key.clone(), val.clone());\n                    helper(keys, idx + 1, grid, acc, out);\n                    acc.remove(key);\n                }\n            }\n        }\n\n        let keys: Vec<String> = self.param_grid.keys().cloned().collect();\n        let mut out = Vec::new();\n        helper(&keys, 0, &self.param_grid, &mut HashMap::new(), &mut out);\n        out\n    }\n\n    /// Fake metric evaluator. In reality, this would invoke a real training\n    /// job and return its validation score. For demo purposes we sample a\n    /// random metric to keep the code fully functional without dependencies\n    /// on heavy ML frameworks.\n    async fn evaluate(\n        &mut self,\n        params: &HashMap<String, HyperParamValue>,\n    ) -> Result<HashMap<String, f64>, OrchestratorError> {\n        let mut rng = rand::thread_rng();\n        // Pretend lower is better for \"loss\".\n        Ok(HashMap::from([(\"loss\".to_string(), rng.gen::<f64>())]))\n    }\n}\n\n#[async_trait]\nimpl HyperParamTuner for GridSearchTuner {\n    async fn run(\n        &mut self,\n        tracker: Arc<dyn ExperimentTracker>,\n        subject: Arc<TuningSubject>,\n    ) -> Result<(), OrchestratorError> {\n        let combos = self.expand_grid();\n        let limit = self.max_trials.unwrap_or(combos.len());\n        for params in combos.into_iter().take(limit) {\n            let metrics = self.evaluate(&params).await?;\n            let trial = Trial {\n                id: self.current_trial_id,\n                params,\n                metrics,\n            };\n            self.current_trial_id += 1;\n\n            tracker.log_trial(&trial).await?;\n            subject.notify(trial)?;\n        }\n        Ok(())\n    }\n}\n\n/// Non-deterministic random-search tuner.\npub struct RandomSearchTuner {\n    param_space: HashMap<String, Vec<HyperParamValue>>,\n    num_trials: usize,\n    current_trial_id: u64,\n}\n\nimpl RandomSearchTuner {\n    pub fn new(param_space: HashMap<String, Vec<HyperParamValue>>, num_trials: usize) -> Self {\n        Self {\n            param_space,\n            num_trials,\n            current_trial_id: 0,\n        }\n    }\n\n    fn sample_params(&self) -> HashMap<String, HyperParamValue> {\n        let mut rng = rand::thread_rng();\n        self.param_space\n            .iter()\n            .map(|(k, v)| {\n                let choice = v.choose(&mut rng).unwrap().clone();\n                (k.clone(), choice)\n            })\n            .collect()\n    }\n\n    async fn evaluate(\n        &mut self,\n        params: &HashMap<String, HyperParamValue>,\n    ) -> Result<HashMap<String, f64>, OrchestratorError> {\n        let mut rng = rand::thread_rng();\n        Ok(HashMap::from([(\"accuracy\".to_string(), rng.gen::<f64>())]))\n    }\n}\n\n#[async_trait]\nimpl HyperParamTuner for RandomSearchTuner {\n    async fn run(\n        &mut self,\n        tracker: Arc<dyn ExperimentTracker>,\n        subject: Arc<TuningSubject>,\n    ) -> Result<(), OrchestratorError> {\n        for _ in 0..self.num_trials {\n            let params = self.sample_params();\n            let metrics = self.evaluate(&params).await?;\n            let trial = Trial {\n                id: self.current_trial_id,\n                params,\n                metrics,\n            };\n            self.current_trial_id += 1;\n\n            tracker.log_trial(&trial).await?;\n            subject.notify(trial)?;\n        }\n        Ok(())\n    }\n}\n\n/// Example observer that prints new trials to stdout.\n/// In production this could push to Prometheus, GUI dashboards, etc.\npub struct StdoutObserver;\n\n#[async_trait]\nimpl TuningObserver for StdoutObserver {\n    async fn on_new_trial(&self, trial: &Trial) -> Result<(), OrchestratorError> {\n        println!(\n            \"🧪 New trial #{} | params={} | metrics={}\",\n            trial.id,\n            json!(trial.params),\n            json!(trial.metrics)\n        );\n        Ok(())\n    }\n}\n\n/// Spawns an asynchronous task that subscribes to a `TuningSubject` and feeds\n/// events into a `TuningObserver`.\npub fn spawn_observer_task<O: 'static + TuningObserver>(\n    subject: Arc<TuningSubject>,\n    observer: Arc<O>,\n) {\n    tokio::spawn(async move {\n        let mut rx = subject.observer_stream();\n        loop {\n            match rx.recv().await {\n                Ok(trial) => {\n                    if let Err(e) = observer.on_new_trial(&trial).await {\n                        eprintln!(\"Observer error: {e}\");\n                    }\n                }\n                Err(broadcast::error::RecvError::Closed) => break,\n                Err(broadcast::error::RecvError::Lagged(_)) => continue,\n            }\n        }\n    });\n}\n\n/// Entrypoint used by integration tests or CLIs.\n///\n/// NOT called automatically by library consumers.\n#[cfg(test)]\nmod tests {\n    use super::*;\n    use std::env::temp_dir;\n\n    #[tokio::test]\n    async fn smoke_grid_search() -> Result<(), OrchestratorError> {\n        // Build tracker.\n        let file_path = temp_dir().join(\"grid_search_trials.jsonl\");\n        let tracker_cfg = TrackerConfig::File { path: file_path };\n        let tracker = TrackerFactory::build(&tracker_cfg)?;\n\n        // Subject & observer wiring.\n        let subject = Arc::new(TuningSubject::new(16));\n        let observer = Arc::new(StdoutObserver);\n        spawn_observer_task(subject.clone(), observer);\n\n        // Define grid.\n        let grid = HashMap::from([\n            (\n                \"lr\".to_string(),\n                vec![\n                    HyperParamValue::Float(0.1),\n                    HyperParamValue::Float(0.01),\n                ],\n            ),\n            (\n                \"batch_size\".to_string(),\n                vec![HyperParamValue::Int(16), HyperParamValue::Int(32)],\n            ),\n        ]);\n\n        let mut tuner = GridSearchTuner::new(grid, None);\n        tuner.run(tracker, subject).await?;\n        Ok(())\n    }\n}\n```", "numLines": 433, "startLine": 1, "totalLines": 433}}

1→//! Generic utilities commonly used across VisuTility Orchestrator.
     2→//!
     3→//! The abstractions in this module are intentionally framework-agnostic:
     4→//! they do not depend on any particular CV/ML crate and can therefore be
     5→//! shared by every layer (Ingress, Data-Ops, Feature-Ops, …).
     6→//!
     7→//! All functions are `#[inline]` where it makes sense to do so, and
     8→//! significant branches are annotated with `#[cold]` to let the optimizer
     9→//! keep hot-paths small.
    10→
    11→use std::{
    12→    fmt,
    13→    fs::File,
    14→    io::Read,
    15→    path::{Path, PathBuf},
    16→    sync::atomic::{AtomicUsize, Ordering},
    17→    time::{Duration, Instant},
    18→};
    19→
    20→use anyhow::{anyhow, Context, Result};
    21→use once_cell::sync::Lazy;
    22→use parking_lot::RwLock;
    23→use serde::de::DeserializeOwned;
    24→use serde::{Deserialize, Serialize};
    25→use thiserror::Error;
    26→use tracing::{debug, error, info, instrument};
    27→
    28→/// VisuTility's generic error type for utility-layer operations.
    29→///
    30→/// We prefer using [`anyhow::Error`] at the top-level application
    31→/// boundary to allow for heterogeneous sources, but within the
    32→/// utility layer we capture the most common failure categories so that
    33→/// callers can still pattern-match when they need to.
    34→#[derive(Debug, Error)]
    35→pub enum UtilError {
    36→    #[error("I/O error: {0}")]
    37→    Io(#[from] std::io::Error),
    38→
    39→    #[error("serialization error: {0}")]
    40→    Serde(#[from] serde_json::Error),
    41→
    42→    #[error("configuration not found at path `{0}`")]
    43→    ConfigNotFound(PathBuf),
    44→
    45→    #[error("task failed: {0}")]
    46→    TaskFailed(String),
    47→}
    48→
    49→/// Generic wrapper around an [`Instant`] which logs the elapsed time at
    50→/// **drop**.  The measurement is therefore *scoped*; as soon as the guard
    51→/// goes out of scope, latency is emitted through the `tracing` facade.
    52→///
    53→/// ```no_run
    54→/// use visu_tility_utils::ScopedTimer;
    55→/// let _g = ScopedTimer::new("heavy_initialisation");
    56→/// // … some expensive code …
    57→— guard drops here and we get a log line with
    58→//   the elapsed time
    59→/// ```
    60→pub struct ScopedTimer<'a> {
    61→    started: Instant,
    62→    label: &'a str,
    63→}
    64→
    65→impl<'a> ScopedTimer<'a> {
    66→    /// Begin measuring elapsed time for the supplied label.
    67→    #[inline]
    68→    pub fn new(label: &'a str) -> Self {
    69→        Self {
    70→            started: Instant::now(),
    71→            label,
    72→        }
    73→    }
    74→
    75→    /// Stop the timer and return the [`Duration`] since creation without
    76→    /// logging. This allows manual control when automatic logging at `drop`
    77→    /// is not desired.
    78→    #[inline]
    79→    pub fn stop(self) -> Duration {
    80→        Instant::now() - self.started
    81→    }
    82→}
    83→
    84→impl<'a> Drop for ScopedTimer<'a> {
    85→    fn drop(&mut self) {
    86→        let elapsed = Instant::now() - self.started;
    87→        info!(
    88→            label = %self.label,
    89→            ms = %elapsed.as_millis(),
    90→            "ScopedTimer finished"
    91→        );
    92→        METRICS
    93→            .write()
    94→            .record_duration(self.label, elapsed.as_secs_f64());
    95→    }
    96→}
    97→
    98→/// Global metrics collector with *zero* external dependencies.  This is
    99→/// intentionally minimal because higher layers might choose to forward these
   100→/// numbers to Prometheus, StatsD, or another monitoring backend.
   101→///
   102→/// Internally it stores *exponential moving averages* so that it can be used
   103→/// in hot-paths without unbounded memory growth.
   104→pub struct Metrics {
   105→    /// Moving average of durations (seconds) per label.
   106→    durations: std::collections::HashMap<String, f64>,
   107→    /// EWMA smoothing factor in `[0,1]`.
   108→    alpha: f64,
   109→}
   110→
   111→impl Metrics {
   112→    fn new(alpha: f64) -> Self {
   113→        Self {
   114→            durations: std::collections::HashMap::new(),
   115→            alpha,
   116→        }
   117→    }
   118→
   119→    /// Record a latency sample under `label`.
   120→    pub fn record_duration(&mut self, label: impl Into<String>, secs: f64) {
   121→        let label = label.into();
   122→        let entry = self.durations.entry(label).or_insert(secs);
   123→        // EWMA: v_t = alpha * x_t + (1-alpha) * v_{t-1}
   124→        *entry = self.alpha * secs + (1.0 - self.alpha) * *entry;
   125→    }
   126→
   127→    /// Return the current EWMA for `label`, if any.
   128→    pub fn duration_avg(&self, label: &str) -> Option<f64> {
   129→        self.durations.get(label).copied()
   130→    }
   131→}
   132→
   133→/// Static metrics instance; tweak the smoothing factor as needed.
   134→/// We protect it with a *fair* RwLock to allow many concurrent readers.
   135→static METRICS: Lazy<RwLock<Metrics>> = Lazy::new(|| RwLock::new(Metrics::new(0.20)));
   136→
   137→/// Typed representation of the global **application config**.
   138→///
   139→/// This is intentionally limited to fields that the utility layer needs
   140→/// to know about; higher layers maintain their own extensions.
