   152→    /// the canonical config.  Can be abused for feature flags, etc.
   153→    #[serde(default)]
   154→    pub user: std::collections::HashMap<String, serde_json::Value>,
   155→}
   156→
   157→#[derive(Debug, Clone, Copy, Serialize, Deserialize)]
   158→pub struct RetryConfig {
   159→    pub max_attempts: usize,
   160→    pub backoff_millis: u64,
   161→}
   162→
   163→impl Default for RetryConfig {
   164→    fn default() -> Self {
   165→        Self {
   166→            max_attempts: 3,
   167→            backoff_millis: 500,
   168→        }
   169→    }
   170→}
   171→
   172→/// Maximum size (bytes) that we allow a configuration file to have before
   173→/// we refuse to load it.  Protects against accidental loading of huge blobs.
   174→const MAX_CONFIG_SIZE: usize = 256 * 1024; // 256 KiB
   175→
   176→/// Load and parse application configuration **once** at start-up.
   177→///
   178→/// The file format is auto-detected based on extension (`.yaml`/`.yml` or
   179→/// `.json`).  The resulting struct is cached in a global `Lazy`.
   180→///
   181→/// Example:
   182→/// ```no_run
   183→/// let cfg = visu_tility_utils::config();
